```cpp
#include <iostream>
#include <memory>
#include <stdexcept>
#include <string>

struct Task {
    std::string name;
    void run() const {
        if (name.empty())
            throw std::invalid_argument("empty");
        std::cout << name << "\n";
    }
};

int main() {
    auto t = std::make_unique<Task>();
    t->name = "go";
    try {
        t->run();
    } catch (const std::exception& e) {
        std::cout << "err: " << e.what() << "\n";
    }
    return 0;
}
